class Solution {
public:
    int minimumOperationsToMakeEqual(int x, int y) {
        if (x == y) return 0;
        if (x > y) {
            int res1 = x - y;
            int res2 = 0;
            int tx = x;
            while (tx % 5 != 0 && tx % 11 != 0) {
                tx--;
                res2++;
            }
            while (tx > y) {
                if (tx % 11 == 0) tx /= 11;
                else if (tx % 5 == 0) tx /= 5;
                res2++;
            }
            res2 += abs(tx - y);
            return min(res1, res2);
        } else {
            return abs(x - y);
        }
    }
};
```
